odd_number = #{oddNumber}, planned_production_id = #{plannedProductionId}, collection_date = #{collectionDate}, applicant = #{applicant}, applicant_date = #{applicantDate}, applicant_status = #{applicantStatus}, reviewer = #{reviewer}, reviewer_date = #{reviewerDate}, reviewer_status = #{reviewerStatus}, review_comments = #{reviewComments}, status = #{status}, remark = #{remark},
